mapper.select:
SELECT e.*, u.username AS applicant_name, au.username AS auditor_name FROM biz_enterprise e LEFT JOIN sys_user u ON e.user_id = u.id -- 关联申请人 LEFT JOIN sys_user au ON e.auditor_id = au.id -- 关联审核人
AND e.company_name LIKE CONCAT('%', #{companyName}, '%')
AND e.industry = #{industry}
AND e.status = #{status}
AND e.building_no = #{buildingNo}
ORDER BY id

